class Solution {
public:
    string smallestNumber(string pattern) {
        int n = pattern.size();
        string res(n + 1, ' ');
        vector<bool> used(10, false);
        for (int i = 0; i <= n; ++i) {
            for (char d = '1'; d <= '9'; ++d) {
                if (used[d - '0']) continue;
                bool ok = true;
                for (int j = 0; j < i && ok; ++j) {
                    if (pattern[j] == 'I' && res[j] >= d) ok = false;
                    if (pattern[j] == 'D' && res[j] <= d) ok = false;
                }
                if (ok) {
                    res[i] = d;
                    used[d - '0'] = true;
                    break;
                }
            }
        }
        return res;
    }
};
```
efficiency: HIGH
time complexity: O(n^2 * 9)
space complexity: O(1)
